using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void Constructor_TotalPages_RoundsUp()
        {
            var items = new List<int> { 1 };
            var list = new PaginatedList<int>(items, 11, 1, 5);

            Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(2, result.TotalPages);
            Assert.Equal(3, result.Count);
            Assert.Contains(1, result);
            Assert.Contains(2, result);
            Assert.Contains(3, result);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 3);

            Assert.Equal(2, result.Count);
            Assert.Contains(4, result);
            Assert.Contains(5, result);
        }

        [Fact]
        public void Constructor_EmptyItems_WorksCorrectly()
        {
            var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);

            Assert.Empty(list);
            Assert.Equal(1, list.PageIndex);
            Assert.Equal(0, list.TotalPages);
            Assert.False(list.HasPreviousPage);
            Assert.False(list.HasNextPage);
        }
    }
}

