using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;
            var model = result.Model as System.Collections.Generic.List<Department>;

            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Details(dept.DepartmentID) as ViewResult;
            var model = result.Model as Department;

            Assert.NotNull(model);
            Assert.Equal(dept.Name, model.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorDropdown()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var instructor = _context.Instructors.First();
            var department = new Department
            {
                Name = "New Department",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = instructor.ID
            };

            var result = _controller.Create(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesDepartment()
        {
            var instructor = _context.Instructors.First();
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = instructor.ID
            };

            _controller.Create(department);

            Assert.True(_context.Departments.Any(d => d.Name == "Physics"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = _controller.Create(department);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Edit(dept.DepartmentID) as ViewResult;
            var model = result.Model as Department;

            Assert.NotNull(model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated Name";

            var result = _controller.Edit(dept);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.AsNoTracking().First();

            var result = _controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Delete(dept.DepartmentID) as ViewResult;
            var model = result.Model as Department;

            Assert.NotNull(model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var id = dept.DepartmentID;

            var result = _controller.DeleteConfirmed(id);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Departments.Find(id));
        }

        #endregion
    }
}

