using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_LoadsCourses()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_LoadsEnrollments()
        {
            var instructor = _context.Instructors.First();
            // Get a course assigned to this instructor
            var courseAssignment = _context.CourseAssignments
                .Include(ca => ca.Course)
                .First(ca => ca.InstructorID == instructor.ID);

            var result = _controller.Index(instructor.ID, courseAssignment.CourseID) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Enrollments);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Details(instructor.ID) as ViewResult;
            var model = result.Model as Instructor;

            Assert.NotNull(model);
            Assert.Equal(instructor.ID, model.ID);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            var model = result.Model as Instructor;

            Assert.NotNull(model);
            Assert.NotNull(model.CourseAssignments);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "1050", "4022" });

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "Teacher");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Edit((int?)instructor.ID) as ViewResult;
            var model = result.Model as Instructor;

            Assert.NotNull(model);
            Assert.Equal(instructor.ID, model.ID);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Delete(instructor.ID) as ViewResult;
            var model = result.Model as Instructor;

            Assert.NotNull(model);
            Assert.Equal(instructor.ID, model.ID);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
        {
            // Use an instructor that has an office assignment for more coverage
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);
            var id = instructor.ID;

            var result = _controller.DeleteConfirmed(id);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(id));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Get an instructor who is an administrator of a department
            var dept = _context.Departments.First(d => d.InstructorID != null);
            var instructorId = dept.InstructorID.Value;

            // The instructor needs an office assignment for the query in the controller
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .Single(i => i.ID == instructorId);
            if (instructor.OfficeAssignment == null)
            {
                _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instructorId, Location = "Temp" });
                _context.SaveChanges();
            }

            _controller.DeleteConfirmed(instructorId);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

