using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { FirstMidName = "John", LastName = "Doe" };
            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Student_Validation_RequiresLastName()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_RequiresFirstMidName()
        {
            var student = new Student
            {
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_Validation_LastNameMaxLength50()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = new string('A', 51),
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_Validation_FirstNameMaxLength50()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_Validation_ValidStudent_NoErrors()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_Validation_ValidInstructor_NoErrors()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Validation_TitleMinLength3()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Validation_TitleMaxLength50()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Validation_CreditsRange0To5()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Validation_CreditsNegative_Invalid()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Validation_ValidCourse_NoErrors()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Validation_NameMinLength3()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Validation_NameMaxLength50()
        {
            var dept = new Department
            {
                Name = new string('A', 51),
                Budget = 100000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Validation_Valid_NoErrors()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_AllValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_LocationMaxLength50()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('A', 51)
            };

            var results = ValidateModel(office);
            Assert.Contains(results, r => r.MemberNames.Contains("Location"));
        }

        [Fact]
        public void OfficeAssignment_ValidLocation_NoErrors()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            var results = ValidateModel(office);
            Assert.Empty(results);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_Properties()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 100
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        #endregion

        #region ViewModels

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var group = new Models.SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2020-09-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2020-09-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void AssignedCourseData_Properties()
        {
            var data = new Models.SchoolViewModels.AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var data = new Models.SchoolViewModels.InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        #endregion

        private static IList<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }
    }
}

