using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanCreateInMemoryDatabase()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudents()
        {
            using var context = TestDbContextFactory.Create();
            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            });
            context.SaveChanges();

            var student = context.Students.Single();
            Assert.Equal("Test", student.FirstMidName);
            Assert.Equal("User", student.LastName);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var ca = context.CourseAssignments.First();
            Assert.True(ca.CourseID > 0);
            Assert.True(ca.InstructorID > 0);
        }

        [Fact]
        public void SchoolContext_InstructorOfficeAssignment_OneToOne()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var instructor = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal(instructor.ID, instructor.OfficeAssignment.InstructorID);
        }

        [Fact]
        public void SchoolContext_CourseDepartment_Relationship()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var course = context.Courses
                .Include(c => c.Department)
                .First();

            Assert.NotNull(course.Department);
        }

        [Fact]
        public void SchoolContext_StudentEnrollment_Relationship()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var student = context.Students
                .Include(s => s.Enrollments)
                .First(s => s.Enrollments.Count > 0);

            Assert.True(student.Enrollments.Count > 0);
        }

        [Fact]
        public void SchoolContext_DepartmentAdministrator_Relationship()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var dept = context.Departments
                .Include(d => d.Administrator)
                .First(d => d.InstructorID != null);

            Assert.NotNull(dept.Administrator);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsData_WhenEmpty()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
        }

        [Fact]
        public void Initialize_DoesNotSeedAgain_WhenStudentsExist()
        {
            using var context = TestDbContextFactory.Create();
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            // Should only have the 1 student we added
            Assert.Equal(1, context.Students.Count());
        }
    }
}

